package agent

import (
	"context"
	"encoding/json"
	"fmt"
	"io"
	"regexp"
	"strings"
	"sync"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/DocumentDrivenDX/ddx/internal/config"
	"github.com/DocumentDrivenDX/ddx/internal/evidence"
)

// ExecuteBeadLoopRuntime carries the non-serializable plumbing and
// per-invocation runtime intent for an execute-bead loop run. Durable knobs
// (assignee, retry caps, harness/model, tier bounds, etc.) live on
// config.ResolvedConfig and are passed via Run's rcfg argument.
type ExecuteBeadLoopRuntime struct {
	Log          io.Writer
	EventSink    io.Writer
	ProgressCh   chan<- ProgressEvent
	PreClaimHook func(ctx context.Context) error
	// RoutePreflight, when non-nil, is invoked between nextCandidate and
	// Claim. It is expected to call upstream ResolveRoute against the
	// loop's resolved (harness, model) and return whatever typed routing
	// error the upstream surfaced — notably agent.ErrHarnessModelIncompatible
	// when the harness allow-list rejects the model. Any non-nil error
	// causes the loop to exit immediately without claiming the bead, with
	// a worker-level execution_failed record naming the rejected pair.
	// DDx does NOT duplicate the upstream allow-list; this gate only
	// consumes the typed-incompatibility surface.
	RoutePreflight func(ctx context.Context, harness, model string) error
	Once           bool
	PollInterval   time.Duration
	NoReview       bool
	LabelFilter    string
	SessionID      string
	WorkerID       string
	ProjectRoot    string
}

// DefaultReviewMaxRetries is the number of reviewer attempts allowed per
// committed result_rev before the loop emits a terminal
// `review-manual-required` event and stops re-executing primary. FEAT-022 §14.
const DefaultReviewMaxRetries = 3

// MaxLoopCooldown is the absolute upper bound the execute-loop will set for
// any execute-loop-retry-after value. Year-scale parks effectively mean
// "never retry" and that should be a deliberate operator choice via
// `ddx bead update --set execute-loop-retry-after=...`, not an automatic
// loop decision. Beyond this cap, the loop refuses to lengthen the cooldown
// further; an operator extending it manually still works.
const MaxLoopCooldown = 24 * time.Hour

// capLoopCooldown clamps a loop-set cooldown duration to MaxLoopCooldown.
// The loop uses this for every SetExecutionCooldown call so no automatic
// path can silently park a bead for a year.
func capLoopCooldown(d time.Duration) time.Duration {
	if d <= 0 {
		return 0
	}
	if d > MaxLoopCooldown {
		return MaxLoopCooldown
	}
	return d
}

type ExecuteBeadReport struct {
	BeadID      string `json:"bead_id"`
	AttemptID   string `json:"attempt_id,omitempty"`
	WorkerID    string `json:"worker_id,omitempty"`
	Harness     string `json:"harness,omitempty"`
	Provider    string `json:"provider,omitempty"`
	Model       string `json:"model,omitempty"`
	Status      string `json:"status"`
	Detail      string `json:"detail,omitempty"`
	SessionID   string `json:"session_id,omitempty"`
	BaseRev     string `json:"base_rev,omitempty"`
	ResultRev   string `json:"result_rev,omitempty"`
	PreserveRef string `json:"preserve_ref,omitempty"`
	RetryAfter  string `json:"retry_after,omitempty"`
	// NoChangesRationale carries the agent's explanation when status == no_changes.
	NoChangesRationale string `json:"no_changes_rationale,omitempty"`
	// ReviewVerdict is the post-merge review verdict (APPROVE, REQUEST_CHANGES,
	// or BLOCK) when a reviewer ran. Empty when review was skipped.
	ReviewVerdict string `json:"review_verdict,omitempty"`
	// ReviewRationale carries the actionable reviewer-authored findings for
	// non-APPROVE review outcomes.
	ReviewRationale string `json:"review_rationale,omitempty"`
	// Tier is the model tier used for the final attempt (cheap, standard, smart).
	// Populated by tier-escalating executors; empty for single-tier attempts.
	Tier string `json:"tier,omitempty"`
	// ProbeResult is a brief summary of the provider health probe at attempt time.
	ProbeResult string `json:"probe_result,omitempty"`
	// CostUSD is the dollar cost of this attempt as reported by the harness.
	// Tier-escalating executors propagate this so the escalation trace can
	// compute wasted/effective spend.
	CostUSD float64 `json:"cost_usd,omitempty"`
	// DurationMS is the wall-clock duration of this attempt.
	DurationMS int64 `json:"duration_ms,omitempty"`
	// Profile routing telemetry. Populated when execute-loop uses a profile
	// ladder rather than an explicit harness/model pin.
	RequestedProfile string `json:"requested_profile,omitempty"`
	RequestedTier    string `json:"requested_tier,omitempty"`
	ResolvedTier     string `json:"resolved_tier,omitempty"`
	EscalationCount  int    `json:"escalation_count,omitempty"`
	FinalTier        string `json:"final_tier,omitempty"`
	// DecompositionRecommendation carries the structured list of recommended
	// sub-bead titles when Status == declined_needs_decomposition. The loop
	// records these on the bead as a `decomposition-recommendation` event so
	// operators (or helix-evolve) can split the bead without re-deriving the
	// recommendation.
	DecompositionRecommendation []string `json:"decomposition_recommendation,omitempty"`
	// DecompositionRationale is a free-form explanation accompanying
	// DecompositionRecommendation. Optional.
	DecompositionRationale string `json:"decomposition_rationale,omitempty"`
}

type ExecuteBeadExecutor interface {
	Execute(ctx context.Context, beadID string) (ExecuteBeadReport, error)
}

type ExecuteBeadExecutorFunc func(ctx context.Context, beadID string) (ExecuteBeadReport, error)

func (f ExecuteBeadExecutorFunc) Execute(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
	return f(ctx, beadID)
}

// SatisfactionChecker evaluates whether a bead that returned no_changes is
// already satisfied and should be closed, or is still unresolved and should
// receive retry suppression. noChangesCount is the cumulative count including
// the current attempt.
//
// When satisfied is true the caller closes the bead with the returned evidence
// string as the detail. When false the caller applies a retry cooldown and
// leaves the bead open.
type SatisfactionChecker interface {
	CheckSatisfied(ctx context.Context, beadID string, noChangesCount int) (satisfied bool, evidence string, err error)
}

// SatisfactionCheckerFunc is a functional adapter for SatisfactionChecker.
type SatisfactionCheckerFunc func(ctx context.Context, beadID string, noChangesCount int) (bool, string, error)

func (f SatisfactionCheckerFunc) CheckSatisfied(ctx context.Context, beadID string, noChangesCount int) (bool, string, error) {
	return f(ctx, beadID, noChangesCount)
}

type ExecuteBeadLoopStore interface {
	ReadyExecution() ([]bead.Bead, error)
	Claim(id, assignee string) error
	Unclaim(id string) error
	Heartbeat(id string) error
	CloseWithEvidence(id, sessionID, commitSHA string) error
	AppendEvent(id string, event bead.BeadEvent) error
	Events(id string) ([]bead.BeadEvent, error)
	SetExecutionCooldown(id string, until time.Time, status, detail string) error
	IncrNoChangesCount(id string) (int, error)
	// Reopen sets a closed bead back to open, appending notes to the bead's
	// Notes field and recording a reopen event. Used by the post-merge review
	// step when the reviewer returns REQUEST_CHANGES or BLOCK.
	Reopen(id, reason, notes string) error
}

// readyDiagnoser is the optional interface the work loop uses to explain an
// empty execution queue. bead.Store satisfies it via ReadyExecutionBreakdown.
type readyDiagnoser interface {
	ReadyExecutionBreakdown() (bead.ReadyExecutionBreakdown, error)
}

// NoReadyWorkBreakdown explains why the execution-ready queue is empty when
// dependency-ready beads exist. Populated on an ExecuteBeadLoopResult when
// NoReadyWork fires and the store exposes ReadyExecutionBreakdown.
type NoReadyWorkBreakdown struct {
	SkippedEpics       []string `json:"skipped_epics,omitempty"`
	SkippedOnCooldown  []string `json:"skipped_on_cooldown,omitempty"`
	SkippedNotEligible []string `json:"skipped_not_eligible,omitempty"`
	SkippedSuperseded  []string `json:"skipped_superseded,omitempty"`
	NextRetryAfter     string   `json:"next_retry_after,omitempty"`
}

// ProgressEvent is the FEAT-006 structured progress event. It is defined
// separately in the server package (server.ProgressEvent); this alias lets
// the agent package emit events without importing the server package.
// The field names and types are identical — the server package deserialises
// these directly from the channel.
//
// Terminal phases: done, preserved, failed.
type ProgressEvent struct {
	EventID   string    `json:"event_id"`
	AttemptID string    `json:"attempt_id"`
	WorkerID  string    `json:"worker_id"`
	ProjectID string    `json:"project_id"`
	BeadID    string    `json:"bead_id"`
	Harness   string    `json:"harness,omitempty"`
	Model     string    `json:"model,omitempty"`
	Profile   string    `json:"profile,omitempty"`
	Phase     string    `json:"phase"`
	PhaseSeq  int       `json:"phase_seq"`
	Heartbeat bool      `json:"heartbeat"`
	TS        time.Time `json:"ts"`
	ElapsedMS int64     `json:"elapsed_ms"`
	Message   string    `json:"message,omitempty"`
}

type ExecuteBeadLoopResult struct {
	Attempts          int                  `json:"attempts"`
	Successes         int                  `json:"successes"`
	Failures          int                  `json:"failures"`
	NoReadyWork       bool                 `json:"no_ready_work,omitempty"`
	NoReadyWorkDetail NoReadyWorkBreakdown `json:"no_ready_work_detail,omitempty"`
	LastSuccessAt     time.Time            `json:"last_success_at,omitempty"`
	LastFailureStatus string               `json:"last_failure_status,omitempty"`
	Results           []ExecuteBeadReport  `json:"results,omitempty"`
}

// ExecuteBeadWorker drains the current single-project execution-ready queue.
// It intentionally does not retry a failed/conflicted bead again in the same
// process run; a later operator-driven invocation can create the next attempt.
type ExecuteBeadWorker struct {
	Store               ExecuteBeadLoopStore
	Executor            ExecuteBeadExecutor
	SatisfactionChecker SatisfactionChecker // nil → count-based default
	Now                 func() time.Time
	// Reviewer, when non-nil, is called after every successful merge to
	// validate the commit against the bead's acceptance criteria. When nil,
	// post-merge review is skipped (same behaviour as --no-review).
	Reviewer BeadReviewer
}

// emitProgress sends a ProgressEvent to runtime.ProgressCh non-blocking.
// If ch is nil or full the event is silently dropped.
func emitProgress(ch chan<- ProgressEvent, evt ProgressEvent) {
	if ch == nil {
		return
	}
	select {
	case ch <- evt:
	default:
	}
}

// newProgressEvent builds a ProgressEvent with a random event_id and current timestamp.
func newProgressEvent(workerID, projectID, beadID, attemptID, harness, model, profile, phase string, phaseSeq int, heartbeat bool, elapsedMS int64) ProgressEvent {
	return ProgressEvent{
		EventID:   "evt-" + randomProgressID(),
		AttemptID: attemptID,
		WorkerID:  workerID,
		ProjectID: projectID,
		BeadID:    beadID,
		Harness:   harness,
		Model:     model,
		Profile:   profile,
		Phase:     phase,
		PhaseSeq:  phaseSeq,
		Heartbeat: heartbeat,
		TS:        time.Now().UTC(),
		ElapsedMS: elapsedMS,
	}
}

func randomProgressID() string {
	return fmt.Sprintf("%x", time.Now().UnixNano())[:8]
}

func (w *ExecuteBeadWorker) Run(ctx context.Context, rcfg config.ResolvedConfig, runtime ExecuteBeadLoopRuntime) (*ExecuteBeadLoopResult, error) {
	if w.Store == nil {
		return nil, fmt.Errorf("execute-bead loop: store is required")
	}
	if w.Executor == nil {
		return nil, fmt.Errorf("execute-bead loop: executor is required")
	}

	now := w.Now
	if now == nil {
		now = time.Now
	}
	assignee := rcfg.Assignee()
	if assignee == "" {
		assignee = "ddx"
	}
	noProgressCooldown := rcfg.NoProgressCooldown()
	if noProgressCooldown <= 0 {
		noProgressCooldown = 6 * time.Hour
	}
	maxNoChangesBeforeClose := rcfg.MaxNoChangesBeforeClose()
	if maxNoChangesBeforeClose <= 0 {
		maxNoChangesBeforeClose = 3
	}
	heartbeatInterval := rcfg.HeartbeatInterval()
	if heartbeatInterval <= 0 {
		heartbeatInterval = bead.HeartbeatInterval
	}
	harness := rcfg.Harness()
	model := rcfg.Model()
	profile := rcfg.Profile()

	result := &ExecuteBeadLoopResult{}
	attempted := make(map[string]struct{})

	emit := func(eventType string, data map[string]any) {
		writeLoopEvent(runtime.EventSink, runtime.SessionID, eventType, data, now().UTC())
	}

	emit("loop.start", map[string]any{
		"worker_id":    runtime.WorkerID,
		"project_root": runtime.ProjectRoot,
		"harness":      harness,
		"model":        model,
		"session_id":   runtime.SessionID,
		"assignee":     assignee,
		"once":         runtime.Once,
	})
	defer func() {
		emit("loop.end", map[string]any{
			"attempts":            result.Attempts,
			"successes":           result.Successes,
			"failures":            result.Failures,
			"last_failure_status": result.LastFailureStatus,
		})
	}()

	for {
		// Respect context cancellation between iterations. Without this check,
		// a Stop() request (which cancels ctx) would only take effect during
		// the idle poll sleep — the loop would happily claim the next ready
		// bead as soon as the current Execute returned, ignoring the cancel.
		if err := ctx.Err(); err != nil {
			return result, err
		}

		candidate, ok, err := w.nextCandidate(attempted, runtime.LabelFilter)
		if err != nil {
			return result, err
		}
		if !ok {
			if result.Attempts == 0 {
				result.NoReadyWork = true
				if diag, ok := w.Store.(readyDiagnoser); ok {
					if breakdown, bErr := diag.ReadyExecutionBreakdown(); bErr == nil {
						result.NoReadyWorkDetail = NoReadyWorkBreakdown{
							SkippedEpics:       breakdown.SkippedEpics,
							SkippedOnCooldown:  breakdown.SkippedOnCooldown,
							SkippedNotEligible: breakdown.SkippedNotEligible,
							SkippedSuperseded:  breakdown.SkippedSuperseded,
							NextRetryAfter:     breakdown.NextRetryAfter,
						}
					}
				}
			}
			if runtime.PollInterval <= 0 {
				return result, nil
			}
			if err := sleepWithContext(ctx, runtime.PollInterval); err != nil {
				return result, err
			}
			continue
		}

		attempted[candidate.ID] = struct{}{}

		// Pre-claim hook: fetch origin + verify ancestry before claiming.
		// On error the bead is skipped for this iteration; the loop
		// continues (ctx is not cancelled).
		if runtime.PreClaimHook != nil {
			if hookErr := runtime.PreClaimHook(ctx); hookErr != nil {
				if runtime.Log != nil {
					_, _ = fmt.Fprintf(runtime.Log, "pre-claim hook: %v (skipping %s)\n", hookErr, candidate.ID)
				}
				emit("preclaim.skipped", map[string]any{
					"bead_id": candidate.ID,
					"reason":  hookErr.Error(),
				})
				continue
			}
		}

		// Routing preflight gate (FEAT-006 D3, ddx-98e6e9ef): consult the
		// upstream typed-incompatibility surface BEFORE claiming. If the
		// configured (harness, model) cannot serve the bead, exit the loop
		// with a worker-level failure record — no claim, no executor
		// invocation, no tier-attempt event burn.
		if runtime.RoutePreflight != nil {
			if rerr := runtime.RoutePreflight(ctx, harness, model); rerr != nil {
				detail := fmt.Sprintf("routing preflight rejected (harness=%s model=%s): %s",
					harness, model, rerr.Error())
				if runtime.Log != nil {
					_, _ = fmt.Fprintf(runtime.Log, "routing preflight: %s (skipping %s, exiting loop)\n",
						detail, candidate.ID)
				}
				emit("preflight.rejected", map[string]any{
					"bead_id": candidate.ID,
					"harness": harness,
					"model":   model,
					"reason":  rerr.Error(),
				})
				report := ExecuteBeadReport{
					BeadID:  candidate.ID,
					Status:  ExecuteBeadStatusExecutionFailed,
					Detail:  detail,
					Harness: harness,
					Model:   model,
				}
				result.Attempts++
				result.Failures++
				result.LastFailureStatus = report.Status
				result.Results = append(result.Results, report)
				return result, nil
			}
		}

		if err := w.Store.Claim(candidate.ID, assignee); err != nil {
			continue
		}

		emit("bead.claimed", map[string]any{
			"bead_id":  candidate.ID,
			"title":    candidate.Title,
			"assignee": assignee,
		})

		if runtime.Log != nil {
			if candidate.Title != "" {
				_, _ = fmt.Fprintf(runtime.Log, "\n▶ %s: %s\n", candidate.ID, candidate.Title)
			} else {
				_, _ = fmt.Fprintf(runtime.Log, "\n▶ %s\n", candidate.ID)
			}
		}

		// Generate a provisional attempt_id for progress events.
		// The real attempt_id is assigned inside ExecuteBead; we use this
		// for queueing/running events and replace with the real one once known.
		provAttemptID := time.Now().UTC().Format("20060102T150405") + "-" + randomProgressID()
		runStart := now()
		phaseSeq := 0
		nextPhase := func(phase string, heartbeat bool) {
			phaseSeq++
			emitProgress(runtime.ProgressCh, newProgressEvent(
				runtime.WorkerID, runtime.ProjectRoot, candidate.ID, provAttemptID,
				harness, model, profile,
				phase, phaseSeq, heartbeat, now().Sub(runStart).Milliseconds(),
			))
		}

		nextPhase("queueing", false)

		hbCtx, hbCancel := context.WithCancel(ctx)
		var hbWG sync.WaitGroup
		hbWG.Add(1)
		go func(beadID string) {
			defer hbWG.Done()
			ticker := time.NewTicker(heartbeatInterval)
			defer ticker.Stop()
			for {
				select {
				case <-hbCtx.Done():
					return
				case <-ticker.C:
					_ = w.Store.Heartbeat(beadID)
				}
			}
		}(candidate.ID)

		nextPhase("running", false)

		report, err := w.Executor.Execute(ctx, candidate.ID)
		hbCancel()
		hbWG.Wait()
		if err != nil {
			report = ExecuteBeadReport{
				BeadID: candidate.ID,
				Status: ExecuteBeadStatusExecutionFailed,
				Detail: err.Error(),
			}
		}
		if report.BeadID == "" {
			report.BeadID = candidate.ID
		}
		if report.Status == "" {
			report.Status = ExecuteBeadStatusExecutionFailed
		}
		if report.Detail == "" {
			report.Detail = ExecuteBeadStatusDetail(report.Status, "", "")
		}

		result.Attempts++

		if report.Status == ExecuteBeadStatusSuccess {
			appendLoopRoutingEvidence(w.Store, candidate.ID, report, now().UTC())
			// Close the bead early when review is skipped. The closure gate
			// (ddx-e30e60a9) accepts this path because closing_commit_sha is
			// set and there is no malformed-APPROVE event to reject.
			reviewApproved := true
			reviewSkipped := w.Reviewer == nil || runtime.NoReview || HasBeadLabel(candidate.Labels, "review:skip")

			if reviewSkipped {
				if err := w.Store.CloseWithEvidence(candidate.ID, report.SessionID, report.ResultRev); err != nil {
					return result, err
				}
			}

			if w.Reviewer != nil && !runtime.NoReview && !HasBeadLabel(candidate.Labels, "review:skip") {
				reviewRes, reviewErr := w.Reviewer.ReviewBead(ctx, candidate.ID, report.ResultRev, report.Harness, report.Model)
				if reviewErr != nil {
					// FEAT-022 §12+§14: classify the failure into the four-class
					// taxonomy and count prior review-error events scoped to the
					// current result_rev. On the Nth failure emit a terminal
					// review-manual-required event instead of yet another
					// review-error, parking the bead so a subsequent loop
					// iteration does NOT re-execute primary.
					class := classifyReviewError(reviewErr, reviewRes)
					prior := countPriorReviewErrors(w.Store, candidate.ID, report.ResultRev)
					attemptCount := prior + 1
					maxRetries := rcfg.ReviewMaxRetries()
					if maxRetries <= 0 {
						maxRetries = DefaultReviewMaxRetries
					}
					errSummary := EventBodySummary{
						InputBytes:  0,
						OutputBytes: 0,
					}
					if reviewRes != nil {
						errSummary = EventBodySummary{
							Harness:     reviewRes.ReviewerHarness,
							Model:       reviewRes.ReviewerModel,
							InputBytes:  reviewRes.InputBytes,
							OutputBytes: reviewRes.OutputBytes,
							ElapsedMS:   reviewRes.DurationMS,
						}
					}
					if attemptCount >= maxRetries {
						body := appendEventSummary(reviewErrorEventBody(class, attemptCount, report.ResultRev, reviewErr.Error()), errSummary)
						_ = w.Store.AppendEvent(candidate.ID, bead.BeadEvent{
							Kind:      "review-manual-required",
							Summary:   class,
							Body:      body,
							Actor:     assignee,
							Source:    "ddx agent execute-loop",
							CreatedAt: now().UTC(),
						})
						// Park the bead with a long cooldown so subsequent
						// loop iterations do NOT re-pick it for primary
						// re-execution. Reviewer-failure invariant (§13) is
						// preserved: the bead is NOT closed.
						parkUntil := now().UTC().Add(capLoopCooldown(MaxLoopCooldown))
						_ = w.Store.SetExecutionCooldown(candidate.ID, parkUntil, "review-manual-required", class)
					} else {
						body := appendEventSummary(reviewErrorEventBody(class, attemptCount, report.ResultRev, reviewErr.Error()), errSummary)
						_ = w.Store.AppendEvent(candidate.ID, bead.BeadEvent{
							Kind:      "review-error",
							Summary:   class,
							Body:      body,
							Actor:     assignee,
							Source:    "ddx agent execute-loop",
							CreatedAt: now().UTC(),
						})
					}
				} else {
					report.ReviewVerdict = string(reviewRes.Verdict)
					report.ReviewRationale = reviewRes.Rationale
					// Persist the full reviewer stream as an artifact so the
					// event body never carries the raw stream (ddx-f8a11202).
					// On error the artifact path is empty and the event body
					// still contains the short verdict summary; callers of this
					// loop can recover the full text from the reviewer session
					// log if the artifact write failed.
					artifactPath, artifactErr := persistReviewerStream(runtime.ProjectRoot, candidate.ID, report.AttemptID, reviewRes.RawOutput)
					if artifactErr != nil && runtime.Log != nil {
						_, _ = fmt.Fprintf(runtime.Log, "reviewer stream artifact: %v\n", artifactErr)
					}

					reviewSummary := EventBodySummary{
						Harness:     reviewRes.ReviewerHarness,
						Model:       reviewRes.ReviewerModel,
						InputBytes:  reviewRes.InputBytes,
						OutputBytes: reviewRes.OutputBytes,
						ElapsedMS:   reviewRes.DurationMS,
					}
					switch reviewRes.Verdict {
					case VerdictApprove:
						// Approved: record the verdict event and then close.
						// Closure must land AFTER the review event so the
						// gate (ddx-e30e60a9) sees the terminal verdict.
						_ = w.Store.AppendEvent(candidate.ID, bead.BeadEvent{
							Kind:      "review",
							Summary:   "APPROVE",
							Body:      appendEventSummary(reviewEventBody("APPROVE", reviewRes.Rationale, artifactPath), reviewSummary),
							Actor:     assignee,
							Source:    "ddx agent execute-loop",
							CreatedAt: now().UTC(),
						})
						if cerr := w.Store.CloseWithEvidence(candidate.ID, report.SessionID, report.ResultRev); cerr != nil {
							return result, cerr
						}
					case VerdictRequestChanges:
						// Needs fixes: record the review verdict, then reopen
						// with findings in notes. The review event must land
						// even on non-approve paths so review-outcomes can
						// attribute the rejection to the originating tier.
						_ = w.Store.AppendEvent(candidate.ID, bead.BeadEvent{
							Kind:      "review",
							Summary:   "REQUEST_CHANGES",
							Body:      appendEventSummary(reviewEventBody("REQUEST_CHANGES", reviewRes.Rationale, artifactPath), reviewSummary),
							Actor:     assignee,
							Source:    "ddx agent execute-loop",
							CreatedAt: now().UTC(),
						})
						reopenNotes := reviewRes.Rationale
						if reopenNotes == "" {
							reopenNotes = reviewRes.RawOutput
						}
						if reopenErr := w.Store.Reopen(candidate.ID, "review: REQUEST_CHANGES", reopenNotes); reopenErr != nil {
							return result, reopenErr
						}
						report.Status = ExecuteBeadStatusReviewRequestChanges
						report.Detail = "post-merge review: REQUEST_CHANGES"
						reviewApproved = false
					case VerdictBlock:
						rationale := strings.TrimSpace(reviewRes.Rationale)
						if rationale == "" {
							_ = w.Store.AppendEvent(candidate.ID, bead.BeadEvent{
								Kind:      "review-malfunction",
								Summary:   "BLOCK without rationale",
								Body:      appendEventSummary(reviewEventBody("BLOCK without rationale", "", artifactPath), reviewSummary),
								Actor:     assignee,
								Source:    "ddx agent execute-loop",
								CreatedAt: now().UTC(),
							})
							report.Status = ExecuteBeadStatusReviewMalfunction
							report.Detail = "post-merge review: malformed BLOCK verdict (missing rationale)"
							report.ReviewRationale = ""
							reviewApproved = false
							break
						}
						// Cannot proceed: record the verdict, then reopen and
						// flag for human with BLOCK marker plus actionable rationale.
						_ = w.Store.AppendEvent(candidate.ID, bead.BeadEvent{
							Kind:      "review",
							Summary:   "BLOCK",
							Body:      appendEventSummary(rationale, reviewSummary),
							Actor:     assignee,
							Source:    "ddx agent execute-loop",
							CreatedAt: now().UTC(),
						})
						blockNotes := "REVIEW:BLOCK\n\n" + rationale
						if reopenErr := w.Store.Reopen(candidate.ID, "review: BLOCK", blockNotes); reopenErr != nil {
							return result, reopenErr
						}
						report.Status = ExecuteBeadStatusReviewBlock
						report.Detail = "post-merge review: BLOCK (flagged for human)"
						reviewApproved = false
					}
				}
			}

			if reviewApproved {
				result.Successes++
				result.LastSuccessAt = now().UTC()
			} else {
				result.Failures++
				result.LastFailureStatus = report.Status
			}
		} else {
			if err := w.Store.Unclaim(candidate.ID); err != nil {
				return result, err
			}
			if report.Status == ExecuteBeadStatusNoChanges {
				count, cerr := w.Store.IncrNoChangesCount(candidate.ID)
				if cerr != nil {
					return result, cerr
				}
				satisfied, evidence, aerr := w.adjudicateNoChanges(ctx, candidate.ID, count, maxNoChangesBeforeClose, report.NoChangesRationale, candidate.Acceptance, runtime.ProjectRoot)
				if aerr != nil {
					return result, aerr
				}
				if satisfied {
					// Adjudication confirmed bead is already satisfied.
					// Set the terminal status BEFORE the close so the late
					// executeBeadLoopEvent append captures "already_satisfied"
					// (not "no_changes"), and emit an early execute-bead
					// evidence event so the closure gate accepts even when
					// BaseRev is empty (test fixtures and genuinely-no-commit
					// satisfied beads).
					report.Status = ExecuteBeadStatusAlreadySatisfied
					if evidence != "" {
						// Checker evidence explains why the bead is being closed;
						// it takes precedence over the executor's attempt detail.
						report.Detail = evidence
					}
					_ = w.Store.AppendEvent(candidate.ID, executeBeadLoopEvent(report, assignee, now().UTC()))
					if cerr := w.Store.CloseWithEvidence(candidate.ID, report.SessionID, report.BaseRev); cerr != nil {
						return result, cerr
					}
					result.Successes++
					result.LastSuccessAt = now().UTC()
				} else {
					// Unresolved: suppress immediate retry so the queue can
					// move on to other beads.
					if shouldSuppressNoProgress(report) {
						retryAfter := now().UTC().Add(capLoopCooldown(noProgressCooldown))
						if cerr := w.Store.SetExecutionCooldown(candidate.ID, retryAfter, report.Status, report.Detail); cerr != nil {
							return result, cerr
						}
						report.RetryAfter = retryAfter.Format(time.RFC3339)
					}
					result.Failures++
					result.LastFailureStatus = report.Status
				}
			} else if report.Status == ExecuteBeadStatusDeclinedNeedsDecomposition {
				// Executor declined the bead because it is too large to
				// deliver in one pass. Record a structured
				// `decomposition-recommendation` event and park the bead
				// long enough that subsequent loop iterations do NOT
				// re-attempt it. An operator (or helix-evolve) clears the
				// cooldown — typically by splitting the bead.
				body, mErr := json.Marshal(map[string]any{
					"rationale":            report.DecompositionRationale,
					"recommended_subbeads": report.DecompositionRecommendation,
					"detail":               report.Detail,
					"base_rev":             report.BaseRev,
					"session_id":           report.SessionID,
				})
				bodyStr := ""
				if mErr == nil {
					bodyStr = string(body)
				} else {
					bodyStr = fmt.Sprintf("rationale=%s\nrecommended_subbeads=%v",
						report.DecompositionRationale, report.DecompositionRecommendation)
				}
				summary := "agent declined: needs decomposition"
				if n := len(report.DecompositionRecommendation); n > 0 {
					summary = fmt.Sprintf("%s (%d sub-beads)", summary, n)
				}
				_ = w.Store.AppendEvent(candidate.ID, bead.BeadEvent{
					Kind:      "decomposition-recommendation",
					Summary:   summary,
					Body:      bodyStr,
					Actor:     assignee,
					Source:    "ddx agent execute-loop",
					CreatedAt: now().UTC(),
				})
				parkUntil := now().UTC().Add(capLoopCooldown(MaxLoopCooldown))
				if err := w.Store.SetExecutionCooldown(candidate.ID, parkUntil, report.Status, report.Detail); err != nil {
					return result, err
				}
				report.RetryAfter = parkUntil.Format(time.RFC3339)
				result.Failures++
				result.LastFailureStatus = report.Status
			} else if report.Status == ExecuteBeadStatusPushFailed {
				// Push failed after a successful local merge/ff. The bead is
				// NOT closed (commits live only locally) — park it under the
				// 24h cap so the loop re-attempts within a reasonable horizon.
				// The push stderr in report.Detail is recorded as last_detail
				// so it surfaces on the bead and on any direct claim attempt.
				parkUntil := now().UTC().Add(capLoopCooldown(MaxLoopCooldown))
				if err := w.Store.SetExecutionCooldown(candidate.ID, parkUntil, report.Status, report.Detail); err != nil {
					return result, err
				}
				report.RetryAfter = parkUntil.Format(time.RFC3339)
				result.Failures++
				result.LastFailureStatus = report.Status
			} else if report.Status == ExecuteBeadStatusPushConflict {
				// The local target ref was advanced and the loop's
				// auto-pull/merge/retry recovery hit a merge conflict it
				// cannot resolve without operator input. Record a
				// `push-conflict` event with the conflict context so the
				// operator can find and resolve it, and park the bead under
				// the same 24h cap as push_failed.
				body, mErr := json.Marshal(map[string]any{
					"detail":     report.Detail,
					"base_rev":   report.BaseRev,
					"result_rev": report.ResultRev,
					"session_id": report.SessionID,
				})
				bodyStr := report.Detail
				if mErr == nil {
					bodyStr = string(body)
				}
				_ = w.Store.AppendEvent(candidate.ID, bead.BeadEvent{
					Kind:      "push-conflict",
					Summary:   "auto-merge after push race could not be resolved",
					Body:      bodyStr,
					Actor:     assignee,
					Source:    "ddx agent execute-loop",
					CreatedAt: now().UTC(),
				})
				parkUntil := now().UTC().Add(capLoopCooldown(MaxLoopCooldown))
				if err := w.Store.SetExecutionCooldown(candidate.ID, parkUntil, report.Status, report.Detail); err != nil {
					return result, err
				}
				report.RetryAfter = parkUntil.Format(time.RFC3339)
				result.Failures++
				result.LastFailureStatus = report.Status
			} else {
				if shouldSuppressNoProgress(report) {
					retryAfter := now().UTC().Add(capLoopCooldown(noProgressCooldown))
					if err := w.Store.SetExecutionCooldown(candidate.ID, retryAfter, report.Status, report.Detail); err != nil {
						return result, err
					}
					report.RetryAfter = retryAfter.Format(time.RFC3339)
				}
				result.Failures++
				result.LastFailureStatus = report.Status
			}
		}

		result.Results = append(result.Results, report)

		// Skip the late execute-bead append for already-satisfied beads —
		// the satisfied path appends its own terminal event before
		// CloseWithEvidence so the closure gate sees execution evidence.
		// Duplicating it here would yield two identical events.
		if report.Status != ExecuteBeadStatusAlreadySatisfied {
			if err := w.Store.AppendEvent(candidate.ID, executeBeadLoopEvent(report, assignee, now().UTC())); err != nil {
				return result, err
			}
		}

		// Emit terminal progress phase event.
		terminalPhase := "failed"
		if report.Status == ExecuteBeadStatusSuccess || report.Status == ExecuteBeadStatusAlreadySatisfied {
			terminalPhase = "done"
		} else if report.PreserveRef != "" {
			terminalPhase = "preserved"
		}
		// Use the real attempt_id from the report if available.
		finalAttemptID := report.AttemptID
		if finalAttemptID == "" {
			finalAttemptID = provAttemptID
		}
		phaseSeq++
		emitProgress(runtime.ProgressCh, ProgressEvent{
			EventID:   "evt-" + randomProgressID(),
			AttemptID: finalAttemptID,
			WorkerID:  runtime.WorkerID,
			ProjectID: runtime.ProjectRoot,
			BeadID:    candidate.ID,
			Harness:   harness,
			Model:     model,
			Profile:   profile,
			Phase:     terminalPhase,
			PhaseSeq:  phaseSeq,
			Heartbeat: false,
			TS:        now().UTC(),
			ElapsedMS: now().Sub(runStart).Milliseconds(),
			Message:   report.Detail,
		})

		emit("bead.result", map[string]any{
			"bead_id":              candidate.ID,
			"status":               report.Status,
			"detail":               report.Detail,
			"session_id":           report.SessionID,
			"result_rev":           report.ResultRev,
			"base_rev":             report.BaseRev,
			"preserve_ref":         report.PreserveRef,
			"no_changes_rationale": report.NoChangesRationale,
			"duration_ms":          now().Sub(runStart).Milliseconds(),
		})

		if runtime.Log != nil {
			_, _ = fmt.Fprintf(runtime.Log, "✓ %s → %s\n", candidate.ID, formatLoopResult(report))
		}

		if runtime.Once {
			return result, nil
		}
	}
}

func (w *ExecuteBeadWorker) nextCandidate(attempted map[string]struct{}, labelFilter string) (bead.Bead, bool, error) {
	ready, err := w.Store.ReadyExecution()
	if err != nil {
		return bead.Bead{}, false, err
	}
	for _, candidate := range ready {
		if _, seen := attempted[candidate.ID]; seen {
			continue
		}
		if labelFilter != "" && !HasBeadLabel(candidate.Labels, labelFilter) {
			continue
		}
		return candidate, true, nil
	}
	return bead.Bead{}, false, nil
}

// appendLoopRoutingEvidence records a kind:routing evidence event on the bead
// from the executor's ExecuteBeadReport, so that review-outcomes analytics can
// attribute a subsequent review verdict to the originating provider/model tier.
// Best-effort: errors and missing-provider cases are silently ignored.
func appendLoopRoutingEvidence(store BeadEventAppender, beadID string, report ExecuteBeadReport, createdAt time.Time) {
	if store == nil || beadID == "" {
		return
	}
	provider := report.Provider
	if provider == "" {
		provider = report.Harness
	}
	if provider == "" {
		return
	}
	body, err := json.Marshal(map[string]any{
		"resolved_provider": provider,
		"resolved_model":    report.Model,
		"fallback_chain":    []string{},
		"requested_profile": report.RequestedProfile,
		"requested_tier":    report.RequestedTier,
		"resolved_tier":     report.ResolvedTier,
		"escalation_count":  report.EscalationCount,
		"final_tier":        report.FinalTier,
	})
	if err != nil {
		return
	}
	summary := "provider=" + provider
	if report.Model != "" {
		summary += " model=" + report.Model
	}
	_ = store.AppendEvent(beadID, bead.BeadEvent{
		Kind:      "routing",
		Summary:   summary,
		Body:      string(body),
		Actor:     "ddx",
		Source:    "ddx agent execute-loop",
		CreatedAt: createdAt,
	})
}

func executeBeadLoopEvent(report ExecuteBeadReport, actor string, createdAt time.Time) bead.BeadEvent {
	parts := []string{}
	if report.Detail != "" {
		parts = append(parts, report.Detail)
	}
	if report.Tier != "" {
		parts = append(parts, fmt.Sprintf("tier=%s", report.Tier))
	}
	if report.ProbeResult != "" {
		parts = append(parts, fmt.Sprintf("probe_result=%s", report.ProbeResult))
	}
	if report.NoChangesRationale != "" {
		parts = append(parts, fmt.Sprintf("rationale: %s", report.NoChangesRationale))
	}
	if report.ReviewRationale != "" {
		parts = append(parts, report.ReviewRationale)
	}
	if report.PreserveRef != "" {
		parts = append(parts, fmt.Sprintf("preserve_ref=%s", report.PreserveRef))
	}
	if report.ResultRev != "" {
		parts = append(parts, fmt.Sprintf("result_rev=%s", report.ResultRev))
	}
	if report.BaseRev != "" {
		parts = append(parts, fmt.Sprintf("base_rev=%s", report.BaseRev))
	}
	if report.RetryAfter != "" {
		parts = append(parts, fmt.Sprintf("retry_after=%s", report.RetryAfter))
	}

	return bead.BeadEvent{
		Kind:      "execute-bead",
		Summary:   report.Status,
		Body:      strings.Join(parts, "\n"),
		Actor:     actor,
		Source:    "ddx agent execute-loop",
		CreatedAt: createdAt,
	}
}

// writeLoopEvent emits one structured JSONL line to sink describing a
// milestone in an execute-bead loop run. Entries use the same envelope as
// the ddx-agent harness (session_id/seq/type/ts/data) so existing log
// aggregators (FormatSessionLogLines, ddx server workers log) can parse
// the stream uniformly. Errors are swallowed: structured logging must
// never break the core execute-loop.
func writeLoopEvent(sink io.Writer, sessionID, eventType string, data map[string]any, ts time.Time) {
	if sink == nil {
		return
	}
	if data == nil {
		data = map[string]any{}
	}
	entry := map[string]any{
		"session_id": sessionID,
		"type":       eventType,
		"ts":         ts.UTC().Format(time.RFC3339Nano),
		"data":       data,
	}
	line, err := json.Marshal(entry)
	if err != nil {
		return
	}
	_, _ = sink.Write(line)
	_, _ = sink.Write([]byte("\n"))
}

// formatLoopResult returns a concise human-readable summary of a bead execution
// result using merged/preserved/error terminology instead of raw status codes.
func formatLoopResult(report ExecuteBeadReport) string {
	switch report.Status {
	case ExecuteBeadStatusSuccess:
		shortRev := report.ResultRev
		if len(shortRev) > 8 {
			shortRev = shortRev[:8]
		}
		if shortRev != "" {
			return fmt.Sprintf("merged (%s)", shortRev)
		}
		return "merged"
	case ExecuteBeadStatusAlreadySatisfied:
		return "already_satisfied"
	case ExecuteBeadStatusNoChanges:
		if report.NoChangesRationale != "" {
			return fmt.Sprintf("no_changes: %s", report.NoChangesRationale)
		}
		return "no_changes"
	default:
		detail := report.Detail
		if detail == "" {
			detail = report.Status
		}
		if report.PreserveRef != "" {
			return fmt.Sprintf("preserved: %s", detail)
		}
		return fmt.Sprintf("error: %s", detail)
	}
}

// reCommitSHA matches a 7-to-40 character lowercase hex string that looks like a
// git commit SHA. Used to detect whether a no_changes rationale cites a prior commit.
var reCommitSHA = regexp.MustCompile(`\b[0-9a-f]{7,40}\b`)

// reTestFuncName matches a Go test function name (TestXxx or BenchmarkXxx).
var reTestFuncName = regexp.MustCompile(`\b(?:Test|Benchmark)[A-Z]\w*\b`)

// rationaleIsSpecific returns true when the rationale string contains a reference
// specific enough to treat a no_changes outcome as already_satisfied on the first
// attempt. Currently this means: the rationale cites a commit SHA (7+ hex chars)
// or a Go test function name. Vague rationales ("nothing to do") return false.
func rationaleIsSpecific(rationale string) bool {
	if rationale == "" {
		return false
	}
	return reCommitSHA.MatchString(rationale) || reTestFuncName.MatchString(rationale)
}

// adjudicateNoChanges runs the no-change adjudication step for a bead.
// It returns (satisfied, evidence, err). When satisfied is true the bead
// should be closed as already_satisfied with the evidence string. When false
// retry suppression (cooldown) should be applied and the bead left open.
//
// If a SatisfactionChecker is configured it is called first. Otherwise:
//   - When the report carries a specific rationale (cites a commit SHA or test
//     name), the bead is closed as already_satisfied on the first occurrence.
//   - Otherwise the default count-based rule applies (close after maxNoChangesBeforeClose).
func (w *ExecuteBeadWorker) adjudicateNoChanges(ctx context.Context, beadID string, noChangesCount, maxNoChangesBeforeClose int, rationale, acceptance, projectRoot string) (bool, string, error) {
	if w.SatisfactionChecker != nil {
		return w.SatisfactionChecker.CheckSatisfied(ctx, beadID, noChangesCount)
	}
	candidate := false
	evidence := ""
	switch {
	case rationaleIsSpecific(rationale):
		candidate = true
		evidence = rationale
	case noChangesCount >= maxNoChangesBeforeClose:
		candidate = true
		evidence = fmt.Sprintf("no_changes on %d consecutive attempt(s); bead treated as already satisfied", noChangesCount)
	}
	if !candidate {
		return false, "", nil
	}
	// Tighten the gate: when AC names structural properties (test functions,
	// deleted files, removed struct fields), refuse already_satisfied unless
	// each property holds in the worktree / rationale. Prevents false closes
	// where a regression suite passes but the AC's specific contract is unmet.
	if claims := ParseACClaims(acceptance); len(claims) > 0 {
		if ok, why := VerifyACClaims(claims, projectRoot, rationale); !ok {
			return false, why, nil
		}
	}
	return true, evidence, nil
}

func shouldSuppressNoProgress(report ExecuteBeadReport) bool {
	if report.BaseRev == "" || report.ResultRev == "" {
		return false
	}
	return report.BaseRev == report.ResultRev
}

// classifyReviewError maps a reviewer error and partial result into one of the
// four FEAT-022 §12 taxonomy classes. Resolution order:
//  1. reviewRes.Error if it's already one of the canonical class identifiers
//     (the reviewer set it explicitly — preferred path).
//  2. The error string text (for backwards-compatible reviewers that only
//     embed the class in their message).
//  3. ErrReviewVerdictUnparseable as a fallback when the strict-parse error
//     leaks through a reviewer that did not set Error.
//  4. Default to transport (network/provider-side failure) when nothing else
//     matches.
func classifyReviewError(reviewErr error, reviewRes *ReviewResult) string {
	if reviewRes != nil {
		switch reviewRes.Error {
		case evidence.OutcomeReviewContextOverflow,
			evidence.OutcomeReviewProviderEmpty,
			evidence.OutcomeReviewUnparseable,
			evidence.OutcomeReviewTransport:
			return reviewRes.Error
		}
	}
	msg := ""
	if reviewErr != nil {
		msg = reviewErr.Error()
	}
	switch {
	case strings.Contains(msg, evidence.OutcomeReviewContextOverflow):
		return evidence.OutcomeReviewContextOverflow
	case strings.Contains(msg, evidence.OutcomeReviewProviderEmpty):
		return evidence.OutcomeReviewProviderEmpty
	case strings.Contains(msg, evidence.OutcomeReviewUnparseable):
		return evidence.OutcomeReviewUnparseable
	case strings.Contains(msg, evidence.OutcomeReviewTransport):
		return evidence.OutcomeReviewTransport
	case reviewErr != nil && strings.Contains(msg, ErrReviewVerdictUnparseable.Error()):
		return evidence.OutcomeReviewUnparseable
	}
	return evidence.OutcomeReviewTransport
}

// reResultRevField extracts the result_rev value from a structured review-error
// event body (one `result_rev=<sha>` line per event, written by
// reviewErrorEventBody). The format is intentionally line-oriented so it
// survives the AppendEvent body cap without losing the rev association.
var reResultRevField = regexp.MustCompile(`(?m)^result_rev=([^\s]+)\s*$`)

// countPriorReviewErrors returns the number of `review-error` events already
// recorded against this bead whose body cites the given result_rev. This is
// the FEAT-022 §14 retry counter — it is event-scoped (no separate counter
// field on the bead) so a fresh result_rev naturally resets the count.
func countPriorReviewErrors(store ExecuteBeadLoopStore, beadID, resultRev string) int {
	if resultRev == "" {
		return 0
	}
	events, err := store.Events(beadID)
	if err != nil {
		return 0
	}
	n := 0
	for _, ev := range events {
		if ev.Kind != "review-error" {
			continue
		}
		m := reResultRevField.FindStringSubmatch(ev.Body)
		if m == nil {
			continue
		}
		if m[1] == resultRev {
			n++
		}
	}
	return n
}

// reviewErrorEventBody is the canonical body shape for review-error and
// review-manual-required events. It carries the failure class, attempt count,
// and result_rev as discrete lines so operators can grep without parsing the
// full reviewer error text. The trailing free-form message is the raw
// reviewer-error string for forensics.
func reviewErrorEventBody(class string, attemptCount int, resultRev, message string) string {
	var b strings.Builder
	fmt.Fprintf(&b, "failure_class=%s\n", class)
	fmt.Fprintf(&b, "attempt_count=%d\n", attemptCount)
	fmt.Fprintf(&b, "result_rev=%s\n", resultRev)
	if message != "" {
		b.WriteString("\n")
		b.WriteString(message)
	}
	return b.String()
}

func sleepWithContext(ctx context.Context, d time.Duration) error {
	if d <= 0 {
		return nil
	}
	timer := time.NewTimer(d)
	defer timer.Stop()
	select {
	case <-ctx.Done():
		return ctx.Err()
	case <-timer.C:
		return nil
	}
}

package agent

// dispatch.go owns the SD-024 dispatch seam shared by execute-bead and the
// post-merge reviewer. It threads durable knobs from a sealed
// config.ResolvedConfig with per-invocation plumbing/intent from an
// AgentRunRuntime through the same service-or-runner routing used by
// RunWithConfigViaService for `ddx agent run`.

import (
	"context"
	"fmt"

	agentlib "github.com/DocumentDrivenDX/agent"
	"github.com/DocumentDrivenDX/ddx/internal/config"
)

// dispatchViaResolvedConfig is the internal SD-024 dispatch seam shared by
// execute-bead's worker and the post-merge reviewer. It resolves how the
// agent invocation is executed (test-injected runner, pre-built service, or
// a fresh service constructed from projectRoot) and routes through
// executeOnService so every durable knob lands on the dispatched request
// exactly once.
//
// Resolution order:
//  1. runner (test injection seam) — used directly via runner.Run after
//     applying any AgentRunRuntime overrides.
//  2. svc (pre-built service) — used via executeOnService.
//  3. Fallback: construct a fresh service via NewServiceFromWorkDir(projectRoot)
//     and dispatch via executeOnService.
//
// Override fields on runtime (HarnessOverride, ModelOverride,
// PermissionsOverride, SessionLogDirOverride) take precedence over the
// matching rcfg accessors when non-empty, so callers can pin one knob for
// a single invocation without re-resolving the full ResolvedConfig.
func dispatchViaResolvedConfig(ctx context.Context, projectRoot string, svc agentlib.DdxAgent, runner AgentRunner, rcfg config.ResolvedConfig, runtime AgentRunRuntime) (*Result, error) {
	if runner != nil {
		return runner.Run(buildRunArgsFromConfig(ctx, rcfg, runtime))
	}
	// DDx-local harnesses (virtual, script) are not upstream service harnesses.
	// Route them through the local Runner so DDX_VIRTUAL_RESPONSES and script
	// directives work correctly via compare and quorum paths, not just agent run.
	harness := runtime.HarnessOverride
	if harness == "" {
		harness = rcfg.Harness()
	}
	if harness == "virtual" || harness == "script" {
		cfg := Config{SessionLogDir: ResolveLogDir(projectRoot, "")}
		r := NewRunner(cfg)
		r.WorkDir = projectRoot
		return r.Run(buildRunArgsFromConfig(ctx, rcfg, runtime))
	}
	if svc == nil {
		built, err := NewServiceFromWorkDir(projectRoot)
		if err != nil {
			return nil, fmt.Errorf("agent: build service: %w", err)
		}
		svc = built
	}
	return executeOnService(ctx, svc, projectRoot, rcfg, runtime)
}

// buildRunArgsFromConfig assembles a RunArgs value for the test
// injection runner path. It applies AgentRunRuntime overrides so a caller
// (execute-bead worker, post-merge reviewer) can pin one durable knob for
// a single invocation without re-resolving the full ResolvedConfig.
func buildRunArgsFromConfig(ctx context.Context, rcfg config.ResolvedConfig, runtime AgentRunRuntime) RunArgs {
	harness := runtime.HarnessOverride
	if harness == "" {
		harness = rcfg.Harness()
	}
	model := runtime.ModelOverride
	if model == "" {
		model = rcfg.Model()
	}
	permissions := runtime.PermissionsOverride
	if permissions == "" {
		permissions = rcfg.Permissions()
	}
	sessionLogDir := runtime.SessionLogDirOverride
	if sessionLogDir == "" {
		sessionLogDir = rcfg.SessionLogDir()
	}

	var opts RunArgs
	opts.Context = ctx
	opts.Harness = harness
	// evidence:allow-unbounded reason="caller is responsible for bounding the prompt before invoking dispatchViaResolvedConfig; downstream executeOnService hits readPromptFileBounded for PromptFile inputs"
	opts.Prompt = runtime.Prompt
	opts.PromptFile = runtime.PromptFile
	opts.PromptSource = runtime.PromptSource
	opts.Correlation = runtime.Correlation
	opts.Model = model
	opts.Provider = rcfg.Provider()
	opts.ModelRef = rcfg.ModelRef()
	opts.Effort = rcfg.Effort()
	opts.Timeout = rcfg.Timeout()
	opts.WallClock = rcfg.WallClock()
	opts.WorkDir = runtime.WorkDir
	opts.Permissions = permissions
	opts.SessionLogDir = sessionLogDir
	return opts
}

package config

import (
	"fmt"
	"os"
	"path/filepath"
	"strings"
	"sync"

	"gopkg.in/yaml.v3"
)

// routingDeprecationWarnOnce ensures the deprecated profile_priority +
// opt-in (profile_ladders / model_overrides) warnings fire only once per
// process even when LoadWithWorkingDir is called many times. Each key
// gets its own sync.Once.
var (
	routingDeprecationWarnOnce sync.Map // key string -> *sync.Once
)

func warnRoutingOnce(key, msg string) {
	v, _ := routingDeprecationWarnOnce.LoadOrStore(key, &sync.Once{})
	v.(*sync.Once).Do(func() {
		fmt.Fprintln(os.Stderr, msg)
	})
}

// ResetRoutingDeprecationWarnings clears the one-time warning latches.
// Tests call this so each test case can observe the warning fresh.
func ResetRoutingDeprecationWarnings() {
	routingDeprecationWarnOnce = sync.Map{}
}

// RoutingMigrationError signals that the loaded config carries the
// removed agent.routing.default_harness field (bead ddx-87fb72c2). The
// field is gone for good; configs must be migrated before DDx will
// load them.
type RoutingMigrationError struct {
	Field string
	Path  string
}

func (e *RoutingMigrationError) Error() string {
	return fmt.Sprintf(
		"%s: %s has been removed. "+
			"Migration: delete the field. The top-level agent.harness is a "+
			"tie-break preference, not a default override. "+
			"See docs/migrations/routing-config.md.",
		e.Path, e.Field)
}

// checkRoutingMigration parses the raw config bytes and reports the
// breaking change cases for agent.routing. Returns a hard error when
// agent.routing.default_harness is present; emits a one-time process
// warning when profile_ladders or model_overrides are set (because
// those fields are now opt-in via --escalate / --override-model).
func checkRoutingMigration(path string, data []byte) error {
	var raw map[string]any
	if err := yaml.Unmarshal(data, &raw); err != nil {
		return nil // YAML errors surface from the validator below
	}
	agent, _ := raw["agent"].(map[string]any)
	if agent == nil {
		return nil
	}
	routing, _ := agent["routing"].(map[string]any)
	if routing == nil {
		return nil
	}
	if _, ok := routing["default_harness"]; ok {
		return &RoutingMigrationError{
			Field: "agent.routing.default_harness",
			Path:  path,
		}
	}
	if _, ok := routing["profile_ladders"]; ok {
		warnRoutingOnce("profile_ladders",
			"warning: agent.routing.profile_ladders is opt-in. "+
				"It is consulted only when --escalate is passed; "+
				"the default execute path ignores it. "+
				"See docs/migrations/routing-config.md.")
	}
	if _, ok := routing["model_overrides"]; ok {
		warnRoutingOnce("model_overrides",
			"warning: agent.routing.model_overrides is opt-in. "+
				"It is consulted only when --override-model is passed; "+
				"the default execute path ignores it. "+
				"See docs/migrations/routing-config.md.")
	}
	return nil
}

// Type aliases for smooth transition
type Config = NewConfig
type Repository = RepositoryConfig

// ConfigError represents a single configuration error
type ConfigError struct {
	Field      string
	Value      string
	Message    string
	Suggestion string
}

func (e *ConfigError) Error() string {
	return fmt.Sprintf("%s: %s", e.Field, e.Message)
}

// ValidationError represents multiple configuration errors
type ValidationError struct {
	Errors []*ConfigError
}

func (e *ValidationError) Error() string {
	if len(e.Errors) == 1 {
		return e.Errors[0].Error()
	}
	return fmt.Sprintf("%d configuration errors found", len(e.Errors))
}

// Load loads configuration using the new simplified approach
func Load() (*Config, error) {
	workingDir, err := os.Getwd()
	if err != nil {
		return nil, fmt.Errorf("failed to get working directory: %w", err)
	}
	return LoadWithWorkingDir(workingDir)
}

// LoadWithWorkingDir loads configuration from a specific working directory
func LoadWithWorkingDir(workingDir string) (*Config, error) {
	if workingDir == "" {
		var err error
		workingDir, err = os.Getwd()
		if err != nil {
			return nil, fmt.Errorf("failed to get working directory: %w", err)
		}
	}

	// Use the new ConfigLoader to load from .ddx/config.yaml only
	loader, err := NewConfigLoaderWithWorkingDir(workingDir)
	if err != nil {
		return nil, fmt.Errorf("failed to create config loader: %w", err)
	}

	// Pre-validation migration check: surface a friendly hard error for
	// removed-field cases (agent.routing.default_harness) and emit
	// one-time warnings for opt-in fields (profile_ladders,
	// model_overrides) before the schema validator sees the file. This
	// happens before LoadConfig so the migration message is what the
	// operator sees.
	configPath := filepath.Join(workingDir, ".ddx", "config.yaml")
	if data, readErr := os.ReadFile(configPath); readErr == nil {
		if migErr := checkRoutingMigration(configPath, data); migErr != nil {
			return nil, migErr
		}
	}

	config, err := loader.LoadConfig()
	if err != nil {
		// If no config file exists, return default config
		if os.IsNotExist(err) || strings.Contains(err.Error(), "no configuration file found") {
			config = DefaultNewConfig()
		} else {
			return nil, err
		}
	}

	// Apply defaults to ensure complete configuration
	config.ApplyDefaults()
	if config.Agent != nil && config.Agent.Routing != nil &&
		len(config.Agent.Routing.ProfilePriority) > 0 {
		fmt.Fprintln(os.Stderr, "warning: agent.routing.profile_priority is deprecated; use agent.routing.profile_ladders.default instead")
	}

	// Override library path with environment variable if set
	if envLibraryPath := os.Getenv("DDX_LIBRARY_BASE_PATH"); envLibraryPath != "" {
		config.Library.Path = envLibraryPath
	}

	// Validate the final configuration
	if err := config.Validate(); err != nil {
		return nil, fmt.Errorf("configuration validation failed: %w", err)
	}

	return config, nil
}

// Validate validates the configuration structure and values (simplified)
func (c *Config) Validate() error {
	var errors []*ConfigError

	// Validate version
	if c.Version == "" {
		errors = append(errors, &ConfigError{
			Field:      "version",
			Message:    "version is required",
			Suggestion: "add 'version: \"1.0\"' to your config",
		})
	}

	// Validate library configuration
	if c.Library != nil && c.Library.Repository != nil {
		if c.Library.Repository.URL == "" {
			errors = append(errors, &ConfigError{
				Field:      "library.repository.url",
				Message:    "library repository URL is required",
				Suggestion: "add a valid Git repository URL",
			})
		}

		if c.Library.Repository.Branch == "" {
			errors = append(errors, &ConfigError{
				Field:      "library.repository.branch",
				Message:    "library repository branch is required",
				Suggestion: "add 'branch: \"main\"' or another valid branch name",
			})
		}
	}

	if len(errors) > 0 {
		return &ValidationError{Errors: errors}
	}

	return nil
}

// Merge combines this config with another, with the other taking precedence
func (c *Config) Merge(other *Config) *Config {
	result := &Config{
		Version: c.Version,
	}

	// Copy library configuration from base
	if c.Library != nil {
		result.Library = &LibraryConfig{
			Path: c.Library.Path,
		}
		if c.Library.Repository != nil {
			result.Library.Repository = &RepositoryConfig{
				URL:    c.Library.Repository.URL,
				Branch: c.Library.Repository.Branch,
			}
		}
	}

	// Override with other's values
	if other.Version != "" {
		result.Version = other.Version
	}
	if other.Library != nil {
		if result.Library == nil {
			result.Library = &LibraryConfig{}
		}
		if other.Library.Path != "" {
			result.Library.Path = other.Library.Path
		}
		if other.Library.Repository != nil {
			if result.Library.Repository == nil {
				result.Library.Repository = &RepositoryConfig{}
			}
			if other.Library.Repository.URL != "" {
				result.Library.Repository.URL = other.Library.Repository.URL
			}
			if other.Library.Repository.Branch != "" {
				result.Library.Repository.Branch = other.Library.Repository.Branch
			}
		}
	}

	return result
}

// ResolveLibraryResource resolves a library resource path
// NOTE: This function is now legacy. New code should load config and use cfg.Library.Path directly.
func ResolveLibraryResource(resourcePath, configPath, workingDir string) (string, error) {
	// Load config to get the authoritative library path (which includes env var override)
	cfg, err := LoadWithWorkingDir(workingDir)
	if err == nil && cfg.Library != nil && cfg.Library.Path != "" {
		// Check if it's an absolute path
		if filepath.IsAbs(resourcePath) {
			return resourcePath, nil
		}

		// Try relative to library path from config
		configPath := filepath.Join(cfg.Library.Path, resourcePath)
		if _, err := os.Stat(configPath); err == nil {
			return configPath, nil
		}

		// Return the config path even if it doesn't exist (for consistency)
		return configPath, nil
	}

	// Fall back to original logic if config loading fails
	if workingDir == "" {
		workingDir, err = os.Getwd()
		if err != nil {
			return "", err
		}
	}

	// Check if it's an absolute path
	if filepath.IsAbs(resourcePath) {
		return resourcePath, nil
	}

	// Try relative to working directory first
	fullPath := filepath.Join(workingDir, resourcePath)
	if _, err := os.Stat(fullPath); err == nil {
		return fullPath, nil
	}

	// Try relative to library directory
	libraryPath := filepath.Join(workingDir, "library", resourcePath)
	if _, err := os.Stat(libraryPath); err == nil {
		return libraryPath, nil
	}

	// Return the original path even if it doesn't exist
	return fullPath, nil
}

// LoadFromFile loads configuration from a specific file path
func LoadFromFile(configPath string) (*Config, error) {
	// Use ConfigLoader to load the file
	loader, err := NewConfigLoaderWithWorkingDir(filepath.Dir(configPath))
	if err != nil {
		return nil, fmt.Errorf("failed to create config loader: %w", err)
	}
	return loader.LoadConfigFromPath(configPath)
}

package config

import "time"

// NewConfig represents the simplified DDx configuration structure
// This aligns with the schema defined in ADR-005 and SD-003
type NewConfig struct {
	Version         string              `yaml:"version" json:"version"`
	Library         *LibraryConfig      `yaml:"library" json:"library"`
	Bead            *BeadConfig         `yaml:"bead,omitempty" json:"bead,omitempty"`
	System          *SystemConfig       `yaml:"system,omitempty" json:"system,omitempty"`
	PersonaBindings map[string]string   `yaml:"persona_bindings,omitempty" json:"persona_bindings,omitempty"`
	UpdateCheck     *UpdateCheckConfig  `yaml:"update_check,omitempty" json:"update_check,omitempty"`
	Agent           *AgentConfig        `yaml:"agent,omitempty" json:"agent,omitempty"`
	Git             *GitConfig          `yaml:"git,omitempty" json:"git,omitempty"`
	Server          *ServerConfig       `yaml:"server,omitempty" json:"server,omitempty"`
	Executions      *ExecutionsConfig   `yaml:"executions,omitempty" json:"executions,omitempty"`
	Cost            *CostConfig         `yaml:"cost,omitempty" json:"cost,omitempty"`
	Workers         *WorkersConfig      `yaml:"workers,omitempty" json:"workers,omitempty"`
	EvidenceCaps    *EvidenceCapsConfig `yaml:"evidence_caps,omitempty" json:"evidence_caps,omitempty"`
	// ReviewMaxRetries caps reviewer attempts per committed result_rev before
	// the execute-loop emits a terminal `review-manual-required` event and
	// parks the bead (FEAT-022 §14). Zero or unset uses the binary default
	// (3). Negative values are treated as unset.
	ReviewMaxRetries *int `yaml:"review_max_retries,omitempty" json:"review_max_retries,omitempty"`
}

// ResolveReviewMaxRetries returns the effective reviewer retry cap for this
// config. Defaults to 3 when unset (matching agent.DefaultReviewMaxRetries).
func (c *NewConfig) ResolveReviewMaxRetries() int {
	if c == nil || c.ReviewMaxRetries == nil || *c.ReviewMaxRetries <= 0 {
		return 3
	}
	return *c.ReviewMaxRetries
}

// EvidenceCapsConfig configures byte-size caps used by the shared
// evidence-assembly primitives (FEAT-022 §1a). Project-level fields
// override the binary defaults; entries in `per_harness` further
// override the project-level values for a specific harness name.
type EvidenceCapsConfig struct {
	MaxPromptBytes       *int                             `yaml:"max_prompt_bytes,omitempty" json:"max_prompt_bytes,omitempty"`
	MaxInlinedFileBytes  *int                             `yaml:"max_inlined_file_bytes,omitempty" json:"max_inlined_file_bytes,omitempty"`
	MaxDiffBytes         *int                             `yaml:"max_diff_bytes,omitempty" json:"max_diff_bytes,omitempty"`
	MaxGoverningDocBytes *int                             `yaml:"max_governing_doc_bytes,omitempty" json:"max_governing_doc_bytes,omitempty"`
	PerHarness           map[string]*EvidenceCapsOverride `yaml:"per_harness,omitempty" json:"per_harness,omitempty"`
	// ContextBudget is the prompt budget label that execute-bead consults
	// when assembling the bead prompt. Empty string means "full budget";
	// "minimal" omits large governing documents (cheap-tier path). See
	// SD-024 §Stage 3 — ExecuteBeadOptions migration.
	ContextBudget string `yaml:"context_budget,omitempty" json:"context_budget,omitempty"`
}

// ResolveContextBudget returns the effective context-budget label for this
// config. Defaults to "" (full budget) when unset.
func (e *EvidenceCapsConfig) ResolveContextBudget() string {
	if e == nil {
		return ""
	}
	return e.ContextBudget
}

// EvidenceCapsOverride is the per-harness override shape inside
// `evidence_caps.per_harness`.
type EvidenceCapsOverride struct {
	MaxPromptBytes       *int `yaml:"max_prompt_bytes,omitempty" json:"max_prompt_bytes,omitempty"`
	MaxInlinedFileBytes  *int `yaml:"max_inlined_file_bytes,omitempty" json:"max_inlined_file_bytes,omitempty"`
	MaxDiffBytes         *int `yaml:"max_diff_bytes,omitempty" json:"max_diff_bytes,omitempty"`
	MaxGoverningDocBytes *int `yaml:"max_governing_doc_bytes,omitempty" json:"max_governing_doc_bytes,omitempty"`
}

// WorkersConfig controls the Add/Remove-worker affordances on the workers
// overview. `default_spec` supplies sane defaults for one-click worker
// dispatch; `max_count` optionally caps concurrent drain workers per project.
type WorkersConfig struct {
	DefaultSpec *WorkerDefaultSpec `yaml:"default_spec,omitempty" json:"default_spec,omitempty"`
	MaxCount    *int               `yaml:"max_count,omitempty" json:"max_count,omitempty"`
	// NoProgressCooldown bounds how long a bead may sit without a phase
	// transition before the execute-loop forces the worker to give up. Parsed
	// via time.ParseDuration (e.g. "6h"). Empty string uses the built-in
	// default (6h). See SD-024 §Config extensions §WorkersConfig.
	NoProgressCooldown string `yaml:"no_progress_cooldown,omitempty" json:"no_progress_cooldown,omitempty"`
	// MaxNoChangesBeforeClose caps the number of consecutive no_changes
	// attempts the execute-loop tolerates before closing the bead as
	// no-progress. Zero or unset uses the built-in default (3). Negative
	// values are treated as unset.
	MaxNoChangesBeforeClose *int `yaml:"max_no_changes_before_close,omitempty" json:"max_no_changes_before_close,omitempty"`
	// HeartbeatInterval is how often a claim owner refreshes its heartbeat
	// while holding a bead. Parsed via time.ParseDuration (e.g. "15s"). Empty
	// string uses the built-in default that matches bead.HeartbeatInterval
	// (30s today).
	HeartbeatInterval string `yaml:"heartbeat_interval,omitempty" json:"heartbeat_interval,omitempty"`
}

// Default values for WorkersConfig resolvers. These mirror the hardcoded
// constants the execute-loop uses today; bead 6/7 of SD-024 wires the
// resolvers into the loop.
const (
	defaultNoProgressCooldown      = 6 * time.Hour
	defaultMaxNoChangesBeforeClose = 3
	defaultHeartbeatInterval       = 30 * time.Second
)

// ResolveNoProgressCooldown returns the effective no-progress cooldown for
// this config. Defaults to 6h when unset or unparseable.
func (w *WorkersConfig) ResolveNoProgressCooldown() time.Duration {
	if w == nil || w.NoProgressCooldown == "" {
		return defaultNoProgressCooldown
	}
	d, err := time.ParseDuration(w.NoProgressCooldown)
	if err != nil || d <= 0 {
		return defaultNoProgressCooldown
	}
	return d
}

// ResolveMaxNoChangesBeforeClose returns the effective max no_changes cap.
// Defaults to 3 when unset or non-positive.
func (w *WorkersConfig) ResolveMaxNoChangesBeforeClose() int {
	if w == nil || w.MaxNoChangesBeforeClose == nil || *w.MaxNoChangesBeforeClose <= 0 {
		return defaultMaxNoChangesBeforeClose
	}
	return *w.MaxNoChangesBeforeClose
}

// ResolveHeartbeatInterval returns the effective heartbeat refresh interval.
// Defaults to 30s (matching bead.HeartbeatInterval today) when unset or
// unparseable.
func (w *WorkersConfig) ResolveHeartbeatInterval() time.Duration {
	if w == nil || w.HeartbeatInterval == "" {
		return defaultHeartbeatInterval
	}
	d, err := time.ParseDuration(w.HeartbeatInterval)
	if err != nil || d <= 0 {
		return defaultHeartbeatInterval
	}
	return d
}

// WorkerDefaultSpec mirrors the knobs a one-click "+ Add worker" dispatch
// honours. Any field left unset falls back to the built-in `ddx work` defaults.
type WorkerDefaultSpec struct {
	Harness string `yaml:"harness,omitempty" json:"harness,omitempty"`
	Profile string `yaml:"profile,omitempty" json:"profile,omitempty"`
	Effort  string `yaml:"effort,omitempty" json:"effort,omitempty"`
	MinTier string `yaml:"min_tier,omitempty" json:"min_tier,omitempty"`
	MaxTier string `yaml:"max_tier,omitempty" json:"max_tier,omitempty"`
}

// CostConfig controls optional cost estimates that DDx cannot infer safely.
type CostConfig struct {
	LocalPer1KTokens *float64 `yaml:"local_per_1k_tokens,omitempty" json:"local_per_1k_tokens,omitempty"`
}

// ExecutionsConfig configures the execute-bead bundle archive (mirror).
type ExecutionsConfig struct {
	Mirror     *ExecutionsMirrorConfig `yaml:"mirror,omitempty" json:"mirror,omitempty"`
	RetainDays int                     `yaml:"retain_days,omitempty" json:"retain_days,omitempty"`
}

// ExecutionsMirrorConfig describes the out-of-band archive target for
// .ddx/executions/<attempt>/ bundles. A configured kind plus path is enough
// to enable mirroring; missing entries leave mirroring disabled.
type ExecutionsMirrorConfig struct {
	Kind    string   `yaml:"kind,omitempty" json:"kind,omitempty"`
	Path    string   `yaml:"path,omitempty" json:"path,omitempty"`
	Include []string `yaml:"include,omitempty" json:"include,omitempty"`
	Async   *bool    `yaml:"async,omitempty" json:"async,omitempty"`
}

// ServerConfig represents server configuration settings.
type ServerConfig struct {
	Addr  string       `yaml:"addr,omitempty" json:"addr,omitempty"`
	Tsnet *TsnetConfig `yaml:"tsnet,omitempty" json:"tsnet,omitempty"`
	// WatchdogDeadline bounds total worker lifetime before the autonomous
	// watchdog considers reaping it. Parsed via time.ParseDuration (e.g. "6h").
	// Empty string uses the built-in default (6h).
	WatchdogDeadline string `yaml:"watchdog_deadline,omitempty" json:"watchdog_deadline,omitempty"`
	// StallDeadline is the max time the current attempt may sit without a
	// phase transition before the watchdog considers it stalled. Parsed via
	// time.ParseDuration (e.g. "1h"). Empty string uses the built-in default (1h).
	StallDeadline string `yaml:"stall_deadline,omitempty" json:"stall_deadline,omitempty"`
}

