package agent

import (
	"context"
	"os"
	"path/filepath"
	"sync/atomic"
	"testing"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/DocumentDrivenDX/ddx/internal/config"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

// TestDrainQueueHistoricalConfigDoesNotFanOut is the AC #10 regression guard
// for ddx-fdd3ea36 / ddx-dd4c423d.
//
// It reproduces the original drain-queue failure mode that produced the
// "19-burn" pattern: the user's real .ddx/config.yaml shape — four
// native-agent endpoints (lmstudio + omlx + lmstudio + lmstudio) plus a
// `gemini` model_override pointing at a `minimax/*` model — combined with
// an empty dispatch spec drove DDx-side synthesis through profile_ladders
// and model_overrides, fanning a single drain into ~19 per-tier attempts.
//
// After the parent's work (ddx-755f5881 default-path fix +
// ddx-87fb72c2 routing-config deprecation), the default execute-loop path
// resolves to a single ResolveRoute call with {Profile: "default"} and the
// loop runs the executor at most once per ready bead. profile_ladders /
// model_overrides are opt-in via --escalate / --override-model only and
// MUST NOT be consulted on this path.
//
// Failure shape this test guards against:
//   - executor invoked many times (≥2, historically up to 19) for one bead
//   - LoadAndResolve fails outright (would mean a deprecation regression)
//
// gemini-binary handling: this test stubs the executor at the loop
// boundary so no harness binary is ever shelled out — gemini's presence
// or absence on $PATH is irrelevant to what we are guarding. The
// regression we care about lives in dispatch + loop, not in the harness
// runner. If a future change reintroduces tier-ladder fan-out into the
// default loop, the executor stub would be invoked >1 time and this test
// would fail loudly. The test is therefore part of the default
// `go test ./...` run and is not gated by build tags or t.Skip.
func TestDrainQueueHistoricalConfigDoesNotFanOut(t *testing.T) {
	// 1. Materialise a config.yaml shaped like the user's real config at
	//    the time of the historical 19-burn:
	//      - four AgentEndpoint entries: lmstudio + omlx + lmstudio + lmstudio
	//      - profile_ladders.default = [cheap, standard, smart]
	//      - model_overrides.cheap   = "minimax/minimax-m2.7" (the model
	//        whose mismatch with the gemini binary drove the fan-out)
	//      - model_overrides.smart   = "gemini/gemini-2.5-flash" (the
	//        binary-installed harness in the historical reproduction)
	//    default_harness is intentionally absent — the routing-config
	//    deprecation makes it a hard load error.
	root := t.TempDir()
	require.NoError(t, os.MkdirAll(filepath.Join(root, ".ddx"), 0o755))
	cfgYAML := `version: "1.0"
library:
  path: ".ddx/plugins/ddx"
  repository:
    url: "https://example.com/lib"
    branch: "main"
agent:
  endpoints:
    - type: lmstudio
      host: "127.0.0.1"
      port: 1234
    - type: omlx
      host: "127.0.0.1"
      port: 8000
    - type: lmstudio
      host: "127.0.0.1"
      port: 1235
    - type: lmstudio
      host: "127.0.0.1"
      port: 1236
  routing:
    profile_ladders:
      default: [cheap, standard, smart]
    model_overrides:
      cheap: "minimax/minimax-m2.7"
      smart: "gemini/gemini-2.5-flash"
`
	require.NoError(t, os.WriteFile(filepath.Join(root, ".ddx", "config.yaml"), []byte(cfgYAML), 0o644))

	// 2. LoadAndResolve with empty overrides except Assignee (the empty-spec
	//    case: no --harness, no --model, no --profile, no --escalate).
	rcfg, err := config.LoadAndResolve(root, config.CLIOverrides{Assignee: "worker"})
	require.NoError(t, err, "historical config (without default_harness) must still load post-deprecation")

	// Sanity: the resolved spec on the default path carries no harness,
	// no model, no profile — the synthesis surfaces that previously drove
	// the 19-burn must all be empty.
	assert.Empty(t, rcfg.Harness(), "default path must not synthesise a harness")
	assert.Empty(t, rcfg.Model(), "default path must not synthesise a model from model_overrides")
	assert.Empty(t, rcfg.Profile(), "default path must not synthesise a profile")
	assert.Empty(t, rcfg.MinTier(), "default path must not synthesise MinTier")
	assert.Empty(t, rcfg.MaxTier(), "default path must not synthesise MaxTier")

	// 3. Single ready bead in a fresh store. We use one bead so that
	//    Once:true draining ends after exactly one queue pass.
	store := bead.NewStore(t.TempDir())
	require.NoError(t, store.Init())
	target := &bead.Bead{ID: "ddx-drain-regression", Title: "Drain regression bead", Priority: 0}
	require.NoError(t, store.Create(target))

	// 4. Counting executor stub. Returns success on the first call so the
	//    loop closes the bead cleanly. Any reintroduction of tier-ladder
	//    fan-out into the default loop would drive >1 invocation here.
	var execCount int32
	worker := &ExecuteBeadWorker{
		Store: store,
		Executor: ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
			n := atomic.AddInt32(&execCount, 1)
			return ExecuteBeadReport{
				BeadID:    beadID,
				Status:    ExecuteBeadStatusSuccess,
				Detail:    "stubbed drain attempt",
				SessionID: "sess-drain",
				ResultRev: "deadbeef",
				// Fail loud if anything calls us a second time within a
				// single bead — that IS the historical fan-out.
				CostUSD:    float64(n),
				DurationMS: int64(n),
			}, nil
		}),
	}

	// Reset routing call counters so we can independently verify that the
	// deprecated tier-ladder helpers stay off the default path.
	ResetRoutingCallCounters()

	result, err := worker.Run(context.Background(), rcfg, ExecuteBeadLoopRuntime{Once: true})
	require.NoError(t, err)
	require.NotNil(t, result)

	// 5. Core regression assertion: at most ONE attempt, never 19.
	got := atomic.LoadInt32(&execCount)
	assert.LessOrEqualf(t, got, int32(1),
		"executor must be invoked at most once per bead on the default drain path; got %d. "+
			"A value >1 (historically 19) means tier-ladder fan-out has been reintroduced.",
		got)
	assert.Equal(t, 1, result.Attempts, "loop should report exactly one attempt for one ready bead")
	assert.Equal(t, 1, result.Successes)
	assert.Equal(t, 0, result.Failures)

	// 6. Belt-and-braces: the deprecated helpers must not be on the
	//    default path's call graph either. ResolveProfileLadder and
	//    ResolveTierModelRef are gated to --escalate; if either fires
	//    here, fan-out is one refactor away from coming back.
	assert.Equal(t, int64(0), ResolveProfileLadderCallCount(),
		"ResolveProfileLadder must not run on the default drain path")
	assert.Equal(t, int64(0), ResolveTierModelRefCallCount(),
		"ResolveTierModelRef must not run on the default drain path")

	// Bead closed cleanly — drain ended in success, not in 19 burned attempts.
	final, err := store.Get(target.ID)
	require.NoError(t, err)
	assert.Equal(t, bead.StatusClosed, final.Status)
}

package agent

import (
	"context"
	"crypto/rand"
	"encoding/hex"
	"encoding/json"
	"errors"
	"fmt"
	"os"
	"regexp"
	"strconv"
	"strings"
	"time"

	agentlib "github.com/DocumentDrivenDX/agent"
	"github.com/DocumentDrivenDX/ddx/internal/config"
)

func containsString(slice []string, s string) bool {
	for _, v := range slice {
		if v == s {
			return true
		}
	}
	return false
}

// Runner executes agent invocations.
type Runner struct {
	registry *harnessRegistry
	Config   Config
	Catalog  *Catalog     // model catalog for routing; defaults to BuiltinCatalog
	Executor Executor     // injected; defaults to OSExecutor
	LookPath LookPathFunc // injected; defaults to exec.LookPath

	// WorkDir is the project root used for loading native agent config.
	WorkDir string
}

// NewRunner creates a runner with defaults.
func NewRunner(cfg Config) *Runner {
	if cfg.Harness == "" {
		cfg.Harness = DefaultHarness
	}
	if cfg.TimeoutMS == 0 {
		cfg.TimeoutMS = DefaultTimeoutMS
	}
	if cfg.WallClockMS == 0 {
		cfg.WallClockMS = DefaultWallClockMS
	}
	if cfg.SessionLogDir == "" {
		cfg.SessionLogDir = DefaultLogDir
	}
	// Build the effective catalog in precedence order (lowest to highest priority):
	//   1. Built-in seed (DefaultModelCatalogYAML — deterministic fallback for smart/standard/cheap)
	//   2. Shared ddx-agent catalog (~/.config/agent/models.yaml — authoritative when installed)
	//   3. User overrides (~/.ddx/model-catalog.yaml — user wins over shared and built-in)
	catalog := BuiltinCatalog.Clone()
	if svc, err := agentlib.New(agentlib.ServiceOptions{}); err == nil {
		ApplyCatalogFromService(context.Background(), catalog, svc)
	}
	if path := DefaultModelCatalogPath(); path != "" {
		if yml, err := LoadModelCatalogYAML(path); err == nil && yml != nil {
			ApplyModelCatalogYAML(catalog, yml)
		}
	}

	r := &Runner{
		registry: newHarnessRegistry(),
		Config:   cfg,
		Catalog:  catalog,
		Executor: &OSExecutor{},
		LookPath: DefaultLookPath,
	}
	r.registry.LookPath = func(file string) (string, error) {
		if r.LookPath != nil {
			return r.LookPath(file)
		}
		return DefaultLookPath(file)
	}
	return r
}

// Run invokes a single agent harness and returns the result.
func (r *Runner) Run(opts RunArgs) (*Result, error) {
	harness, harnessName, err := r.resolveHarness(opts)
	if err != nil {
		return nil, err
	}

	// If the provider flag was consumed as a harness name (e.g. "agent",
	// "local"), clear it so downstream code (RunAgent →
	// resolveEmbeddedAgentProvider) doesn't try to look it up as a
	// ddx-agent config provider name.
	if opts.Provider != "" {
		resolved := resolveHarnessAlias(opts.Provider)
		if resolved == harnessName {
			opts.Provider = ""
		}
	}

	// virtual harness: replay from dictionary instead of executing a binary.
	if harnessName == "virtual" {
		return runVirtualFn(r, opts)
	}

	// Agent harness: run in-process via the embedded agent library.
	if harnessName == "agent" {
		return RunAgent(r, opts)
	}

	// Script harness: execute directives against the real filesystem and git.
	if harnessName == "script" {
		return runScriptFn(r, opts)
	}

	// HTTP-provider harnesses (lmstudio, openrouter, and any other harness
	// registered with IsHTTPProvider=true and no Binary) have no CLI binary
	// to exec. They MUST route through the embedded agent runtime, which
	// speaks OpenAI-compatible APIs and can be pointed at any provider via
	// --provider. Without this dispatch, the exec path below would call
	// ExecuteInDir with harness.Binary="", producing a zero-duration
	// "exec: no command" error (see ddx-501e87ef: cheap-tier attempts on
	// lmstudio were burning <1s and escalating straight to smart tier).
	if harness.IsHTTPProvider && harness.Binary == "" {
		agentOpts := opts
		// Surface the harness name as the provider so the embedded runtime
		// knows which .agent/config.yaml provider block to use. If the caller
		// already specified --provider, preserve their choice.
		if agentOpts.Provider == "" {
			agentOpts.Provider = harnessName
		}
		return RunAgent(r, agentOpts)
	}

	prompt, err := r.resolvePrompt(opts)
	if err != nil {
		return nil, err
	}

	model := r.resolveModel(opts, harnessName)

	// Warn on deprecated explicit model pin.
	if model != "" {
		cat := r.catalog()
		if dp, deprecated := cat.CheckDeprecatedPin(model, harness.Surface); deprecated {
			fmt.Fprintf(os.Stderr, "agent: model %q is deprecated; use %q instead\n", model, dp.ReplacedBy)
		}
	}

	// Warn on unknown model
	if model != "" && len(harness.Models) > 0 && !containsString(harness.Models, model) {
		fmt.Fprintf(os.Stderr, "agent: model %q is not a known model for harness %q; available models: %s\n",
			model, harnessName, strings.Join(harness.Models, ", "))
	}

	// Warn on unknown effort
	if opts.Effort != "" {
		levels := r.resolveReasoningLevels(harnessName, harness)
		if len(levels) > 0 && !containsString(levels, opts.Effort) {
			fmt.Fprintf(os.Stderr, "agent: effort %q is not a known reasoning level for harness %q; available levels: %s\n",
				opts.Effort, harnessName, strings.Join(levels, ", "))
		}
	}

	timeout := r.resolveTimeout(opts)
	wallClock := r.resolveWallClock(opts)

	// Build args with the resolved prompt (may have come from file)
	resolvedOpts := opts
	// evidence:allow-unbounded reason="prompt is the bounded output of r.resolvePrompt → readPromptFileBounded (FEAT-022 §3)"
	resolvedOpts.Prompt = prompt
	resolvedOpts.Permissions = resolvePermissions(r.Config.Permissions, opts.Permissions)
	args := BuildArgs(harness, buildArgsInputFromRunArgs(resolvedOpts), model)
	stdin := ""
	if harness.PromptMode == "stdin" {
		stdin = prompt
	}

	// Execute
	start := time.Now()
	parentCtx := opts.Context
	if parentCtx == nil {
		parentCtx = context.Background()
	}
	ctx, cancel := context.WithCancel(parentCtx)
	defer cancel()
	ctx = withExecutionTimeout(ctx, timeout)
	ctx = withExecutionWallClock(ctx, wallClock)

	// Use ExecuteInDir when WorkDir is set — this handles harnesses like
	// claude that have no --cwd flag by setting cmd.Dir on the subprocess.
	execDir := ""
	if opts.WorkDir != "" && harness.WorkDirFlag == "" {
		execDir = opts.WorkDir
	}

	// Claude streaming path: when running against the real OSExecutor, pipe
	// claude's stream-json stdout through parseClaudeStream so operators see
	// real-time progress (tool calls, turn counts, elapsed) in
	// `ddx server workers log` instead of a 20–40 minute silence. The path
	// falls back to the legacy buffered --print behaviour automatically if
	// the CLI rejects the stream-json flags.
	if harnessName == "claude" {
		if _, isOS := r.Executor.(*OSExecutor); isOS {
			result, err := runClaudeWithFallbackFn(r, ctx, harness, harnessName, model, resolvedOpts, prompt, execDir, timeout)
			if err == nil && result != nil {
				finalizeClaudeResult(r, result, opts, prompt, time.Since(start))
				return result, nil
			}
			// If the streaming path failed outright (not just claude exit != 0),
			// fall through to the classic Executor path so behaviour degrades
			// gracefully.
		}
	}

	execResult, execErr := r.Executor.ExecuteInDir(ctx, harness.Binary, args, stdin, execDir)
	elapsed := time.Since(start)

	result := r.processResult(harnessName, model, harness, execResult, execErr, elapsed, ctx)
	promptSource := opts.PromptSource
	if promptSource == "" {
		if opts.PromptFile != "" {
			promptSource = opts.PromptFile
		} else {
			promptSource = "inline"
		}
	}
	r.logSession(result, len(prompt), prompt, promptSource, opts.Correlation)
	r.recordRoutingOutcome(result, elapsed, opts)
	return result, nil
}

// RunWithConfig is the SD-024 successor to Run. It accepts a sealed
// ResolvedConfig (durable knobs) and an AgentRunRuntime (plumbing +
// per-invocation intent), assembles an equivalent RunArgs, and
// delegates to Run. Behavior is identical to Run with an
// equivalently-populated RunArgs.
//
// Stage 2 of SD-024: this method exists alongside Run; production
// callers have not migrated yet.
func (r *Runner) RunWithConfig(ctx context.Context, rcfg config.ResolvedConfig, runtime AgentRunRuntime) (*Result, error) {
	sessionLogDir := runtime.SessionLogDirOverride
	if sessionLogDir == "" {
		sessionLogDir = rcfg.SessionLogDir()
	}
	opts := RunArgs{
		Context:       ctx,
		Harness:       rcfg.Harness(),
		Prompt:        runtime.Prompt,
		PromptFile:    runtime.PromptFile,
		PromptSource:  runtime.PromptSource,
		Correlation:   runtime.Correlation,
		Model:         rcfg.Model(),
		Provider:      rcfg.Provider(),
		ModelRef:      rcfg.ModelRef(),
		Effort:        rcfg.Effort(),
		Timeout:       rcfg.Timeout(),
		WallClock:     rcfg.WallClock(),
		WorkDir:       runtime.WorkDir,
		Permissions:   rcfg.Permissions(),
		SessionLogDir: sessionLogDir,
	}
	return r.Run(opts)
}

// ValidateForExecuteLoop checks harness availability and model compatibility
// before any beads are claimed. Returns an error if the harness is not
// available or if the model is clearly incompatible with the harness
// (e.g. a local agent preset used with a non-agent harness). Emits a
// deprecation warning to stderr if the model pin is deprecated.
//
// Call this in execute-loop before starting the worker so failures are
// surfaced before any beads are claimed rather than mid-execution.
func (r *Runner) ValidateForExecuteLoop(harnessName, model, provider, modelRef string) error {
	if harnessName == "" {
		return nil // no explicit harness; routing will pick at claim time
	}

	h, name, err := r.resolveHarness(RunArgs{Harness: harnessName})
	if err != nil {
		return err
	}

	if model != "" {
		cat := r.catalog()

		// Warn about deprecated model pins before any bead is claimed.
		if dp, deprecated := cat.CheckDeprecatedPin(model, h.Surface); deprecated {
			fmt.Fprintf(os.Stderr, "execute-loop: model %q is deprecated for harness %q; use %q instead\n",
				model, name, dp.ReplacedBy)
		}
	}
	return nil
}

